    vector<long long> A(n_land);
    for (int i = 0; i < n_land; i++) {
        A[i] = landStartTime[i] + landDuration[i];
        if (A[i] < minA) 
            minA = A[i];
    }

    long long minB = LLONG_MAX;
    vector<long long> B(n_water);
    for (int j = 0; j < n_water; j++) {
        B[j] = waterStartTime[j] + waterDuration[j];
        if (B[j] < minB) 
            minB = B[j];
    }

    vector<pair<long long, long long>> waterItems2;
    vector<long long> values_water;
    for (int j = 0; j < n_water; j++) {
        long long val = minA + waterDuration[j];
        values_water.push_back(val);
        waterItems2.push_back({B[j], val});
    }
    sort(waterItems2.begin(), waterItems2.end());
    vector<long long> minValWater(waterItems2.size());
    for (int i = 0; i < waterItems2.size(); i++) {
        if (i == 0) 
            minValWater[i] = waterItems2[i].second;
        else 
            minValWater[i] = min(minValWater[i-1], waterItems2[i].second);
    }

    vector<pair<long long, long long>> landItems2;
    vector<long long> values_land;
    for (int i = 0; i < n_land; i++) {
        long long val = minB + landDuration[i];
        values_land.push_back(val);
        landItems2.push_back({A[i], val});
    }
    sort(landItems2.begin(), landItems2.end());
    vector<long long> minValLand(landItems2.size());
    for (int i = 0; i < landItems2.size(); i++) {
        if (i == 0)
            minValLand[i] = landItems2[i].second;
        else
            minValLand[i] = min(minValLand[i-1], landItems2[i].second);
    }

    long long candidate1 = *max_element(values_water.begin(), values_water.end());
    long long candidate2 = *max_element(values_land.begin(), values_land.end());
    long long high_bound = max(candidate1, candidate2);
    long long low_bound = 0;
    long long ans = high_bound;

    while (low_bound <= high_bound) {
        long long mid = low_bound + (high_bound - low_bound) / 2;
        bool Option1 = false;
        auto it1 = upper_bound(waterItems2.begin(), waterItems2.end(), make_pair(mid, LLONG_MAX));
        if (it1 != waterItems2.begin()) {
            int idx = it1 - waterItems2.begin();
            long long min_val = minValWater[idx-1];
            if (min_val <= mid) {
                Option1 = true;
            }
        }

        bool Option2 = false;
        auto it2 = upper_bound(landItems2.begin(), landItems2.end(), make_pair(mid, LLONG_MAX));
