            int idx = it2 - landItems2.begin();
            long long min_val = minValLand[idx-1];
            if (min_val <= mid) {
                Option2 = true;
            }
        }

        if (Option1 || Option2) {
            ans = mid;
            high_bound = mid - 1;
        } else {
            low_bound = mid + 1;
        }
    }

    return ans;
}
