#include <vector>
#include <algorithm>
#include <climits>

using namespace std;

long long solve(vector<long long> landStartTime, vector<long long> landDuration, vector<long long> waterStartTime, vector<long long> waterDuration) {
    int n_land = landStartTime.size();
    int n_water = waterStartTime.size();
    long long INF = LLONG_MAX;

    vector<long long> landEnd;
    for (int i = 0; i < n_land; i++) {
        landEnd.push_back(landStartTime[i] + landDuration[i]);
    }

    struct WaterRide {
        long long start;
        long long duration;
        long long total;
    };
    vector<WaterRide> waterList;
    for (int j = 0; j < n_water; j++) {
        long long s = waterStartTime[j];
        long long d = waterDuration[j];
        WaterRide w = {s, d, s + d};
        waterList.push_back(w);
    }
    sort(waterList.begin(), waterList.end(), [](const WaterRide& a, const WaterRide& b) {
        return a.start < b.start;
    });

    vector<long long> prefix_min_duration(n_water, INF);
    vector<long long> suffix_min_total(n_water, INF);

    if (n_water > 0) {
        prefix_min_duration[0] = waterList[0].duration;
        for (int i = 1; i < n_water; i++) {
            prefix_min_duration[i] = min(prefix_min_duration[i-1], waterList[i].duration);
        }

        suffix_min_total[n_water-1] = waterList[n_water-1].total;
        for (int i = n_water-2; i >= 0; i--) {
            suffix_min_total[i] = min(suffix_min_total[i+1], waterList[i].total);
        }
    }

    long long min_case1 = INF;
    for (long long end_time : landEnd) {
        WaterRide dummy;
        dummy.start = end_time;
        auto it = upper_bound(waterList.begin(), waterList.end(), dummy, [](const WaterRide& a, const WaterRide& b) {
            return a.start < b.start;
        });
        int idx = it - waterList.begin();
        int pos = idx - 1;

        long long candidate1 = INF;
        if (pos >= 0) {
            candidate1 = end_time + prefix_min_duration[pos];
        }

        long long candidate2 = INF;
        if (idx < n_water) {
            candidate2 = suffix_min_total[idx];
        }

        min_case1 = min(min_case1, min(candidate1, candidate2));
    }

    vector<long long> waterTotal;
    for (int j = 0; j < n_water; j++) {
        waterTotal.push_back(waterStartTime[j] + waterDuration[j]);
    }

    struct LandRide {
        long long start;
        long long duration;
        long long total;
    };
    vector<LandRide> landList;
    for (int i = 0; i < n_land; i++) {
        long long s = landStartTime[i];
        long long d = landDuration[i];
        LandRide land = {s, d, s + d};
        landList.push_back(land);
    }
    sort(landList.begin(), landList.end(), [](const LandRide& a, const LandRide& b) {
        return a.start < b.start;
    });

    vector<long long> prefix_min_land_duration(n_land, INF);
    vector<long long> suffix_min_landTotal(n_land, INF);

    if (n_land > 0) {
        prefix_min_land_duration[0] = landList[0].duration;
        for (int i = 1; i < n_land; i++) {
            prefix_min_land_duration[i] = min(prefix_min_land_duration[i-1], landList[i].duration);
        }

        suffix_min_landTotal[n_land-1] = landList[n_land-1].total;
        for (int i = n_land-2; i >= 0; i--) {
            suffix_min_landTotal[i] = min(suffix_min_landTotal[i+1], landList[i].total);
        }
    }

    long long min_case2 = INF;
    for (long long total : waterTotal) {
        LandRide dummy_land;
        dummy_land.start = total;
        auto it_land = upper_bound(landList.begin(), landList.end(), dummy_land, [](const LandRide& a, const LandRide& b) {
            return a.start < b.start;
        });
        int idx_land = it_land - landList.begin();
        int pos_land = idx_land - 1;

        long long cand1 = INF;
        if (pos_land >= 0) {
            cand1 = total + prefix_min_land_duration[pos_land];
        }

        long long cand2 = INF;
        if (idx_land < n_land) {
            cand2 = suffix_min_landTotal[idx_land];
        }

        min_case2 = min(min_case2, min(cand1, cand2));
    }

    return min(min_case1, min_case2);
}
